"use client";

import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useReducedMotion } from 'framer-motion';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import HTMLFlipBook from 'react-pageflip';
import { CoverLeaf, ImageLeaf, TextLeaf, BackCoverLeaf } from './BookLeaves';
import type { BookDefinition, GlossData } from './types';

// A playful default trail color per page dot — pass your own via `dotColors`.
const DEFAULT_DOT_COLORS = ['#c1583f', '#4a7363', '#dab465', '#5a8598'];

export interface StoryBookProps {
    book: BookDefinition;
    /** Resolved gloss data for every word the book uses, keyed by word. You
     *  fetch/build this however your dictionary data is stored. */
    glosses: Record<string, GlossData>;
    /** Overrides the page-dot color rotation. */
    dotColors?: string[];
}

/** Minimal surface of the PageFlip instance this component actually calls. */
interface PageFlipHandle {
    pageFlip(): {
        flipNext(): void;
        flipPrev(): void;
        flip(page: number): void;
        getCurrentPageIndex(): number;
        getPageCount(): number;
    };
}

/**
 * The reusable animated reader: any BookDefinition renders through this —
 * new books need only a data file, never new reader code. Pages are real
 * physical leaves (react-pageflip / StPageFlip) with drag-to-turn and corner
 * curl; each story page contributes an image leaf and a text leaf, which
 * pair up into a two-page spread whenever the viewport is wide enough.
 *
 * Requires `import '@dictionary-ui/react/styles.css'` once in your app.
 */
export default function StoryBook({ book, glosses, dotColors = DEFAULT_DOT_COLORS }: StoryBookProps) {
    const flipRef = useRef<PageFlipHandle | null>(null);
    const [leafIndex, setLeafIndex] = useState(0);
    const [ready, setReady] = useState(false);
    // react-pageflip manipulates the DOM directly and has no meaningful SSR
    // output; a mount-guard (rather than a framework-specific "no SSR" API)
    // keeps this package portable across Next.js, Vite, CRA, Remix, etc.
    const [mounted, setMounted] = useState(false);
    const reduceMotion = useReducedMotion();

    useEffect(() => setMounted(true), []);

    const totalLeaves = book.pages.length * 2 + 2;
    const lastLeaf = totalLeaves - 1;

    const currentPageOfBook = leafIndex > 0 && leafIndex < lastLeaf
        ? Math.min(book.pages.length - 1, Math.floor((leafIndex - 1) / 2))
        : -1;

    // The front cover renders alone in the widget's right slot; the back
    // cover renders alone in the LEFT slot (it's the final leaf, reached
    // after everything else has "turned" to that side) — opposite
    // directions, so they need opposite correction. Rather than resizing the
    // widget itself — react-pageflip caches each leaf's absolute position
    // and doesn't recompute on a CSS-transition-driven parent resize, which
    // causes real layout bugs — shift the whole widget visually with a
    // transform instead. Transforms don't touch the library's own layout
    // math, so this is safe.
    const isFrontCover = leafIndex === 0;
    const isBackCover = leafIndex === lastLeaf;
    const isSingleLeaf = isFrontCover || isBackCover;
    const singleLeafShift = isFrontCover ? '-25%' : isBackCover ? '25%' : '0%';

    const goToLeaf = useCallback((leaf: number) => {
        flipRef.current?.pageFlip().flip(Math.max(0, Math.min(lastLeaf, leaf)));
    }, [lastLeaf]);

    useEffect(() => {
        const onKey = (e: KeyboardEvent) => {
            if (!ready) return;
            if (e.key === 'ArrowRight') flipRef.current?.pageFlip().flipNext();
            if (e.key === 'ArrowLeft') flipRef.current?.pageFlip().flipPrev();
        };
        window.addEventListener('keydown', onKey);
        return () => window.removeEventListener('keydown', onKey);
    }, [ready]);

    return (
        <div className="dui-stage">
            <div className="dui-book-shadow" style={{ width: '100%', display: 'flex', justifyContent: 'center', maxWidth: 1040 }}>
                <div
                    style={{
                        width: '100%',
                        transform: isSingleLeaf ? `translateX(${singleLeafShift})` : 'translateX(0)',
                        transition: 'transform 0.5s ease-out',
                    }}
                >
                    {mounted ? (
                        <HTMLFlipBook
                            ref={flipRef}
                            className="dui-flipbook"
                            style={{}}
                            startPage={0}
                            size="stretch"
                            width={480}
                            height={620}
                            minWidth={280}
                            maxWidth={560}
                            minHeight={380}
                            maxHeight={720}
                            drawShadow
                            flippingTime={reduceMotion ? 1 : 650}
                            usePortrait
                            startZIndex={10}
                            autoSize
                            maxShadowOpacity={0.4}
                            showCover
                            mobileScrollSupport={false}
                            swipeDistance={20}
                            showPageCorners
                            disableFlipByClick
                            clickEventForward
                            useMouseEvents
                            renderOnlyPageLengthChange={false}
                            onInit={() => setReady(true)}
                            onFlip={(e: { data: number }) => setLeafIndex(e.data)}
                        >
                            <CoverLeaf book={book} glosses={glosses} />
                            {book.pages.flatMap((page, i) => [
                                <ImageLeaf key={`${page.id}-img`} alt={page.imageAlt} imageUrl={page.imageUrl} seed={i + 1} />,
                                <TextLeaf key={`${page.id}-text`} page={page} glosses={glosses} />,
                            ])}
                            <BackCoverLeaf note={book.note} onRestart={() => goToLeaf(0)} />
                        </HTMLFlipBook>
                    ) : (
                        // Reserves the same footprint so nothing jumps once the reader mounts.
                        <div style={{ width: '100%', aspectRatio: '480 / 620', maxWidth: 560, margin: '0 auto', borderRadius: '0.6rem', background: 'var(--dui-paper-shade, #f0e2c4)' }} />
                    )}
                </div>
            </div>

            {/* Controls */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '1rem', width: '100%', maxWidth: 1040 }}>
                <button
                    onClick={() => flipRef.current?.pageFlip().flipPrev()}
                    disabled={leafIndex === 0}
                    className="dui-nav-button"
                    style={{
                        display: 'inline-flex', alignItems: 'center', gap: '0.5rem',
                        padding: '0.875rem 1.5rem', borderRadius: '9999px', fontWeight: 700,
                        textTransform: 'uppercase', fontSize: '0.875rem', letterSpacing: '0.03em',
                    }}
                >
                    <ChevronLeft size={20} /> Back
                </button>

                <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
                    {book.pages.map((page, i) => (
                        <button
                            key={page.id}
                            aria-label={`Go to page ${i + 1}: ${page.label}`}
                            onClick={() => goToLeaf(1 + i * 2)}
                            className="dui-page-dot"
                            style={{
                                width: '0.875rem', height: '0.875rem', borderRadius: '9999px', border: 'none', padding: 0, cursor: 'pointer',
                                background: i === currentPageOfBook ? 'var(--dui-book-accent, #a8402c)' : dotColors[i % dotColors.length],
                                opacity: i === currentPageOfBook ? 1 : 0.55,
                                transform: i === currentPageOfBook ? 'scale(1.5)' : 'scale(1)',
                            }}
                        />
                    ))}
                </div>

                <button
                    onClick={() => flipRef.current?.pageFlip().flipNext()}
                    disabled={leafIndex === lastLeaf}
                    className="dui-nav-button"
                    style={{
                        display: 'inline-flex', alignItems: 'center', gap: '0.5rem',
                        padding: '0.875rem 1.5rem', borderRadius: '9999px', fontWeight: 700,
                        textTransform: 'uppercase', fontSize: '0.875rem', letterSpacing: '0.03em',
                    }}
                >
                    Next <ChevronRight size={20} />
                </button>
            </div>

            <p style={{ fontSize: '0.75rem', fontStyle: 'italic', textAlign: 'center', color: 'var(--dui-ink-soft, #7c6a52)', opacity: 0.7 }}>
                Drag a page corner to turn it, or use the arrow keys.
            </p>
        </div>
    );
}

"use client";

import React, { forwardRef } from 'react';
import { motion } from 'framer-motion';
import { GlossLine } from '../gloss/GlossWord';
import PagePlaceholder from './PagePlaceholder';
import type { BookDefinition, GlossData } from './types';

/**
 * The individual leaves react-pageflip renders. Each must be a single
 * forwarded-ref div at the top level (the library measures/transforms it
 * directly), so these stay presentational — all reading state lives in the
 * parent <StoryBook>. Requires `@dictionary-ui/react/styles.css` for the
 * `dui-*` classes referenced here.
 */

export const CoverLeaf = forwardRef<HTMLDivElement, {
    book: BookDefinition;
    glosses: Record<string, GlossData>;
}>(function CoverLeaf({ book, glosses }, ref) {
    return (
        <div ref={ref} className="page" data-density="hard">
            <div className="dui-hard-cover" style={{ position: 'relative' }}>
                {/* Full-bleed art — the illustration IS the cover, not a boxed inset. */}
                <div style={{ position: 'absolute', inset: 0 }}>
                    <PagePlaceholder alt={book.coverImageAlt} imageUrl={book.coverImageUrl} seed={0} />
                </div>
                {/* Title sits over the art, like a printed cover, on a scrim
                    that guarantees legibility regardless of the art. */}
                <div
                    className="dui-cover-scrim"
                    style={{ position: 'absolute', insetInline: 0, bottom: 0, padding: '5rem 1.5rem 2rem', textAlign: 'center' }}
                >
                    <h1
                        className="dui-title-outline"
                        style={{ fontSize: '1.75rem', fontWeight: 700, lineHeight: 1.2, margin: '0 0 0.75rem', color: 'var(--dui-cover-ink)' }}
                    >
                        <GlossLine tokens={book.title} glosses={glosses} />
                    </h1>
                    <p style={{ fontStyle: 'italic', fontSize: '1.05rem', opacity: 0.9, margin: 0, color: 'var(--dui-cover-ink)' }}>
                        {book.subtitle}
                    </p>
                </div>
            </div>
        </div>
    );
});

export const ImageLeaf = forwardRef<HTMLDivElement, { alt: string; imageUrl?: string; seed: number }>(
    function ImageLeaf({ alt, imageUrl, seed }, ref) {
        return (
            <div ref={ref} className="page">
                <div className="dui-leaf dui-image-leaf">
                    <PagePlaceholder alt={alt} imageUrl={imageUrl} seed={seed} />
                </div>
            </div>
        );
    }
);

export const TextLeaf = forwardRef<HTMLDivElement, {
    page: BookDefinition['pages'][number];
    glosses: Record<string, GlossData>;
}>(function TextLeaf({ page, glosses }, ref) {
    return (
        <div ref={ref} className="page">
            <div
                className="dui-leaf dui-text-leaf"
                style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '2rem 1.75rem' }}
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                    {page.lines.map((line, i) => (
                        <div key={i}>
                            <p style={{ fontSize: '1.375rem', fontWeight: 700, lineHeight: 1.3, margin: 0, color: i % 2 === 1 ? 'var(--dui-book-accent)' : 'var(--dui-ink)' }}>
                                <GlossLine tokens={line.text} glosses={glosses} />
                            </p>
                            {line.translation && (
                                <p style={{ fontStyle: 'italic', fontSize: '0.95rem', marginTop: '0.25rem', color: 'var(--dui-ink-soft)' }}>
                                    {line.translation}
                                </p>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
});

export const BackCoverLeaf = forwardRef<HTMLDivElement, { note?: string; onRestart: () => void }>(
    function BackCoverLeaf({ note, onRestart }, ref) {
        const paragraphs = (note ?? '').split('\n\n');
        return (
            <div ref={ref} className="page" data-density="hard">
                <div className="dui-hard-cover dui-hard-cover--column" style={{ overflowY: 'auto' }}>
                    <div style={{ padding: '2.5rem 2rem' }}>
                        <h2 style={{ fontSize: '1.1rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '1.25rem', opacity: 0.9 }}>
                            Notes
                        </h2>
                        {paragraphs.map((p, i) => (
                            <p
                                key={i}
                                style={{
                                    marginBottom: '0.75rem', lineHeight: 1.6,
                                    fontSize: i === paragraphs.length - 1 ? '0.75rem' : '0.9rem',
                                    opacity: i === paragraphs.length - 1 ? 0.6 : 0.9,
                                }}
                                dangerouslySetInnerHTML={{
                                    __html: p
                                        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
                                        .replace(/\*(.+?)\*/g, '<em>$1</em>'),
                                }}
                            />
                        ))}
                        <motion.button
                            whileTap={{ scale: 0.96 }}
                            onClick={onRestart}
                            style={{
                                marginTop: '1rem', display: 'inline-flex', alignItems: 'center', gap: '0.5rem',
                                padding: '0.6rem 1.25rem', borderRadius: '9999px', border: '1px solid rgba(255,255,255,0.3)',
                                background: 'transparent', color: 'inherit', fontWeight: 700, textTransform: 'uppercase',
                                fontSize: '0.75rem', letterSpacing: '0.05em', cursor: 'pointer',
                            }}
                        >
                            Read Again
                        </motion.button>
                    </div>
                </div>
            </div>
        );
    }
);

"use client";

import { motion, useReducedMotion } from 'framer-motion';
import { Feather, Sparkles } from 'lucide-react';

export interface PagePlaceholderProps {
    alt: string;
    imageUrl?: string;
    /** Derives a stable tint per page so a book doesn't look flat. Change TINTS to your own palette. */
    seed?: number;
}

const TINTS = [
    'linear-gradient(155deg, #c1583f, #8f331f)',
    'linear-gradient(155deg, #4a7363, #294038)',
    'linear-gradient(155deg, #dab465, #a97a2e)',
    'linear-gradient(155deg, #5a8598, #2c4a56)',
];
const INK = '#f3e6c8';

/**
 * A page's illustration slot. Renders the real image once you supply
 * `imageUrl`; until then, a placeholder that reads as "the art for this
 * page is on its way" rather than a broken image.
 */
export default function PagePlaceholder({ alt, imageUrl, seed = 0 }: PagePlaceholderProps) {
    const reduceMotion = useReducedMotion();

    if (imageUrl) {
        return (
            // eslint-disable-next-line @next/next/no-img-element
            <img src={imageUrl} alt={alt} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        );
    }

    return (
        <div
            style={{
                position: 'relative', width: '100%', height: '100%',
                display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden',
                background: TINTS[seed % TINTS.length],
            }}
        >
            <motion.div
                style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.75rem', textAlign: 'center', padding: '0 2rem' }}
                animate={reduceMotion ? undefined : { y: [0, -6, 0] }}
                transition={reduceMotion ? undefined : { duration: 4.5, repeat: Infinity, ease: 'easeInOut' }}
            >
                <div style={{ position: 'relative' }}>
                    <Feather size={40} strokeWidth={1.5} style={{ opacity: 0.8, color: INK }} />
                    <motion.span
                        style={{ position: 'absolute', top: '-0.5rem', right: '-1rem' }}
                        animate={reduceMotion ? undefined : { opacity: [0.3, 1, 0.3], scale: [0.85, 1.15, 0.85] }}
                        transition={reduceMotion ? undefined : { duration: 2.6, repeat: Infinity, ease: 'easeInOut' }}
                    >
                        <Sparkles size={16} style={{ color: '#e6c987' }} />
                    </motion.span>
                </div>
                <p style={{ fontSize: '0.65rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', opacity: 0.9, color: INK, margin: 0 }}>
                    Illustration on its way
                </p>
                <p style={{ fontSize: '0.875rem', fontStyle: 'italic', opacity: 0.95, maxWidth: '20rem', color: INK, margin: 0 }}>
                    {alt}
                </p>
            </motion.div>
        </div>
    );
}

import type { GlossData, GlossToken } from '../gloss/types';

/**
 * A book is pure data — <StoryBook> renders any book fitting this shape, so
 * adding book #2 through book #200 means writing a data file, not new code.
 *
 * A line of text is a sequence of tokens: dictionary words (rendered with a
 * gloss tooltip and click-to-play audio via <GlossLine>) interleaved with
 * literal punctuation/spacing. Glosses are resolved by YOU (from your own
 * dictionary data, however it's stored) and passed in as a plain
 * `Record<string, GlossData>` — the reader itself doesn't fetch anything.
 */
export interface BookLine {
    /** The line's tokens — words (gloss-linked) and literal text mixed together. */
    text: GlossToken[];
    /** A translation/gloss shown beneath the line, if bilingual. */
    translation?: string;
}

export interface BookPage {
    id: string;
    /** Short label for the progress rail, e.g. "mui'n — bear". */
    label: string;
    lines: BookLine[];
    /** Alt text / placeholder caption describing the scene. */
    imageAlt: string;
    /** Real illustration, once available. Falls back to a placeholder. */
    imageUrl?: string;
}

export interface BookDefinition {
    slug: string;
    title: GlossToken[];
    subtitle: string;
    coverImageAlt: string;
    coverImageUrl?: string;
    pages: BookPage[];
    /** Closing note, plain text with **bold** / *italic* markdown-lite emphasis. */
    note?: string;
}

export type { GlossData };

"use client";

import React, { useEffect, useState } from 'react';
import { playRecording } from '../audio/play-audio';
import { cn } from '../utils';
import type { GlossData, GlossToken } from './types';

// Injected once globally rather than per-instance — many GlossWords on one
// page would otherwise duplicate an identical <style> block each.
let stylesInjected = false;
function useGlossWordStyles() {
    useEffect(() => {
        if (stylesInjected || typeof document === 'undefined') return;
        stylesInjected = true;
        const style = document.createElement('style');
        style.setAttribute('data-dui', 'gloss-word');
        style.textContent = `
            .dui-gloss-word:hover > .dui-gloss-word__bridge,
            .dui-gloss-word:focus-within > .dui-gloss-word__bridge {
                display: block;
            }
        `;
        document.head.appendChild(style);
    }, []);
}

export interface GlossWordProps {
    /** The lookup key — used for the aria-label; display defaults to this. */
    word: string;
    /** Text actually shown, if different from `word` (e.g. a capitalized form). */
    display?: string;
    data?: GlossData;
    className?: string;
}

/**
 * A single word with a hover/focus gloss tooltip and click-to-play audio.
 * Router-agnostic: the tooltip's "open dictionary entry" link is a plain
 * `<a>` — if you're on Next.js/Remix/etc. and want client-side navigation,
 * swap it for your framework's Link in a copy-pasted version.
 *
 * The tooltip sits flush against the word (no gap) with its own bottom
 * padding acting as an invisible hover "bridge" — without it, moving the
 * mouse from the word up into the tooltip crosses a dead zone that belongs
 * to neither element, so hover (and the tooltip) drops before the cursor
 * arrives. `:focus-within` keeps it open while the link inside is
 * keyboard-focused, too.
 */
export default function GlossWord({ word, display, data, className }: GlossWordProps) {
    const [playing, setPlaying] = useState(false);
    const text = display ?? word;
    useGlossWordStyles();

    if (!data) return <span className={className}>{text}</span>;

    const play = async () => {
        if (!data.audioUrl) return;
        try {
            setPlaying(true);
            const audio = await playRecording(data.audioUrl);
            audio.addEventListener('ended', () => setPlaying(false));
            audio.addEventListener('error', () => setPlaying(false));
        } catch {
            setPlaying(false);
        }
    };

    return (
        <span
            className={cn('dui-gloss-word', className)}
            style={{
                position: 'relative',
                display: 'inline-block',
                borderBottom: '2px dotted currentColor',
                cursor: data.audioUrl ? 'pointer' : 'help',
                color: playing ? 'var(--dui-accent, #a8402c)' : undefined,
            }}
            tabIndex={0}
            role={data.audioUrl ? 'button' : undefined}
            aria-label={data.audioUrl ? `${text}: ${data.gloss}. Play recording.` : `${text}: ${data.gloss}`}
            onClick={data.audioUrl ? play : undefined}
            onKeyDown={
                data.audioUrl
                    ? (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); play(); } }
                    : undefined
            }
        >
            {text}
            <span className="dui-gloss-word__bridge" style={{
                position: 'absolute', left: 0, bottom: '100%', zIndex: 20,
                display: 'none', width: 'max-content', maxWidth: '16rem', paddingBottom: '0.5rem',
            }}>
                <span style={{
                    display: 'block',
                    background: 'var(--dui-tooltip-bg, #1a1a1a)',
                    color: 'var(--dui-tooltip-fg, #fff)',
                    fontSize: '0.75rem', fontWeight: 700, lineHeight: 1.5,
                    padding: '0.75rem', borderRadius: 'var(--dui-radius, 0.5rem)',
                    boxShadow: '0 4px 16px rgba(0,0,0,0.25)',
                }}>
                    {data.gloss}
                    {data.pron && <span style={{ display: 'block', fontWeight: 400, marginTop: '0.25rem' }}>say: {data.pron}</span>}
                    {data.audioUrl && (
                        <span style={{ display: 'block', fontWeight: 400, marginTop: '0.25rem', opacity: 0.8 }}>
                            click the word to hear it
                        </span>
                    )}
                    {data.href && (
                        <a
                            href={data.href}
                            onClick={(e) => e.stopPropagation()}
                            style={{ display: 'block', fontWeight: 400, marginTop: '0.5rem', textDecoration: 'underline', color: 'inherit' }}
                        >
                            open dictionary entry →
                        </a>
                    )}
                </span>
            </span>
        </span>
    );
}

/** Renders a line of mixed word/literal tokens, resolving each word against a gloss map. */
export function GlossLine({
    tokens,
    glosses,
}: {
    tokens: GlossToken[];
    glosses: Record<string, GlossData>;
}) {
    return (
        <>
            {tokens.map((t, i) =>
                'literal' in t
                    ? <React.Fragment key={i}>{t.literal}</React.Fragment>
                    : <GlossWord key={i} word={t.word} display={t.display} data={glosses[t.word]} />
            )}
        </>
    );
}

export interface GlossData {
    /** The definition/gloss shown in the tooltip. */
    gloss: string;
    /** Pronunciation guide, e.g. "mu·iin". */
    pron?: string;
    /** Playable audio URL — if set, the word becomes clickable and plays it. */
    audioUrl?: string;
    /** Link to a full dictionary entry — if set, the tooltip offers it. */
    href?: string;
}

export type GlossToken = { word: string; display?: string } | { literal: string };

"use client";

/**
 * Shared audio playback for recordings.
 *
 * Two problems this solves:
 *  - On some systems (notably Linux/PipeWire) the audio output device is
 *    suspended until the first sound, clipping the start of the first clip.
 *    A short burst of silence on the first user interaction wakes it up.
 *  - `new Audio(url).play()` without a kept reference can be garbage-collected
 *    mid-playback; the module holds the current element.
 *
 * Framework-agnostic — takes only a playable URL, no project-specific data
 * shape (manifest format, API routes, etc.) baked in.
 */

const STOP_EVENT = 'dictionary-ui-audio-play';

// 0.3s of silence as a tiny WAV data URI (44-byte header + zeroed samples).
const SILENCE = (() => {
    const rate = 8000;
    const seconds = 0.3;
    const samples = Math.floor(rate * seconds);
    const buf = new ArrayBuffer(44 + samples * 2);
    const v = new DataView(buf);
    const str = (o: number, s: string) => {
        for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i));
    };
    str(0, 'RIFF'); v.setUint32(4, 36 + samples * 2, true); str(8, 'WAVE');
    str(12, 'fmt '); v.setUint32(16, 16, true); v.setUint16(20, 1, true); v.setUint16(22, 1, true);
    v.setUint32(24, rate, true); v.setUint32(28, rate * 2, true); v.setUint16(32, 2, true); v.setUint16(34, 16, true);
    str(36, 'data'); v.setUint32(40, samples * 2, true);
    let b = '';
    new Uint8Array(buf).forEach((byte) => { b += String.fromCharCode(byte); });
    return 'data:audio/wav;base64,' + btoa(b);
})();

let warmed = false;
let current: HTMLAudioElement | null = null;

async function warmUp() {
    if (warmed) return;
    warmed = true;
    try {
        const s = new Audio(SILENCE);
        s.volume = 1; // real (silent) samples must reach the sink to resume it
        await s.play();
        await new Promise((r) => setTimeout(r, 250));
    } catch {
        /* autoplay rejection etc. — playback below still works */
    }
}

/** Stop whatever is playing (also fired by other players via the stop event). */
export function stopAudio() {
    current?.pause();
    current = null;
}

if (typeof window !== 'undefined') {
    window.addEventListener(STOP_EVENT, () => {
        current?.pause();
        current = null;
    });
}

/**
 * Play a recording. Returns the HTMLAudioElement so callers can track
 * ended/error state. Any other playing recording is stopped first.
 */
export async function playRecording(url: string): Promise<HTMLAudioElement> {
    window.dispatchEvent(new CustomEvent(STOP_EVENT));
    await warmUp();
    const audio = new Audio(url);
    audio.preload = 'auto';
    current = audio;
    const clear = () => { if (current === audio) current = null; };
    audio.addEventListener('ended', clear);
    audio.addEventListener('error', clear);
    await audio.play();
    return audio;
}

/** Joins truthy class names. No Tailwind-merge semantics — kept dependency-free
 *  so this package doesn't force a specific styling toolchain on consumers. */
export function cn(...classes: Array<string | false | null | undefined>): string {
    return classes.filter(Boolean).join(' ');
}
